			svc := &fakeSellService{err: tc.err}
			body, _ := json.Marshal(dto.SellBetRequest{MarketID: 1, Amount: 10, Outcome: "YES"})
			req := httptest.NewRequest(http.MethodPost, "/v0/sell", bytes.NewReader(body))
